const DirectMessage = require("../models/DirectMessage");
const User = require("../models/User");
const ApiError = require("../utils/ApiError");
const catchAsync = require("../utils/catchAsync");

const normalizeParticipants = (a, b) => [Number(a), Number(b)].sort((x, y) => x - y);

const ensureFriendship = async (meId, otherId) => {
  const me = await User.findOne({ id: meId });
  const other = await User.findOne({ id: otherId });
  if (!me || !other) throw new ApiError(404, "User not found");
  if (!me.friends.includes(otherId) || !other.friends.includes(meId)) {
    throw new ApiError(403, "You can only message your friends");
  }
  return other;
};

// GET /api/dm/:friendId/messages
const getDirectMessages = catchAsync(async (req, res) => {
  const meId = req.user.id;
  const friendId = Number(req.params.friendId);
  if (!Number.isFinite(friendId)) throw new ApiError(400, "Invalid friend id");
  if (friendId === meId) throw new ApiError(400, "Cannot open DM with yourself");

  await ensureFriendship(meId, friendId);

  const participants = normalizeParticipants(meId, friendId);
  const dmMessages = await DirectMessage.find({ participants }).sort({ timestamp: 1 });

  res.status(200).json(dmMessages);
});

// POST /api/dm/:friendId/messages
const postDirectMessage = catchAsync(async (req, res) => {
  const meId = req.user.id;
  const friendId = Number(req.params.friendId);
  const { content, attachmentUrl, attachmentName, attachmentMimeType } = req.body || {};

  if (!Number.isFinite(friendId)) throw new ApiError(400, "Invalid friend id");
  if (friendId === meId) throw new ApiError(400, "Cannot message yourself");

  const trimmedContent = typeof content === "string" ? content.trim() : "";
  if (!trimmedContent && !attachmentUrl) {
    throw new ApiError(400, "Message content or attachment is required");
  }

  await ensureFriendship(meId, friendId);

  const newMessage = new DirectMessage({
    participants: normalizeParticipants(meId, friendId),
    senderId: meId,
    content: trimmedContent,
    attachmentUrl: attachmentUrl || null,
    attachmentName: attachmentName || null,
    attachmentMimeType: attachmentMimeType || null,
  });

  await newMessage.save();
  res.status(201).json(newMessage);
});

// POST /api/dm/:friendId/call-events
const postDmCallStartEvent = catchAsync(async (req, res) => {
  const meId = req.user.id;
  const friendId = Number(req.params.friendId);
  const { callType = "audio" } = req.body || {};

  if (!Number.isFinite(friendId)) throw new ApiError(400, "Invalid friend id");
  if (friendId === meId) throw new ApiError(400, "Cannot call yourself");

  await ensureFriendship(meId, friendId);

  const normalizedCallType = callType === "video" ? "video" : "audio";
  const newMessage = new DirectMessage({
    participants: normalizeParticipants(meId, friendId),
    senderId: meId, // The person who started the call
    type: "system",
    systemKind: "call_started",
    content: `${req.user.username} started a ${normalizedCallType} call.`,
  });

  await newMessage.save();
  res.status(201).json(newMessage);
});

module.exports = {
  getDirectMessages,
  postDirectMessage,
  postDmCallStartEvent,
};

const User = require("../models/User");
const ApiError = require("../utils/ApiError");
const catchAsync = require("../utils/catchAsync");

// ─── Send Friend Request ───────────────────────────────────────────────────────
// POST /api/friends/request   { toUsername }
const sendRequest = catchAsync(async (req, res) => {
  const { toUsername } = req.body;
  const fromId = req.user.id; // injected by verifyToken

  if (!toUsername) throw new ApiError(400, "Username is required");

  // Find target user by username (case-insensitive)
  const toUser = await User.findOne({ username: { $regex: new RegExp(`^${toUsername}$`, "i") } });
  if (!toUser) throw new ApiError(404, "User not found");

  if (toUser.id === fromId) throw new ApiError(400, "You cannot add yourself");

  // Already friends?
  if (toUser.friends.includes(fromId)) throw new ApiError(400, "Already friends");

  // Request already sent?
  const alreadySent = toUser.friendRequests.some(r => r.from === fromId && r.status === "pending");
  if (alreadySent) throw new ApiError(400, "Friend request already sent");

  // They already sent us a request — auto-accept
  const fromUser = await User.findOne({ id: fromId });
  const theirRequest = fromUser.friendRequests.find(r => r.from === toUser.id && r.status === "pending");
  if (theirRequest) {
    theirRequest.status = "accepted";
    if (!fromUser.friends.includes(toUser.id)) fromUser.friends.push(toUser.id);
    if (!toUser.friends.includes(fromId)) toUser.friends.push(fromId);
    await fromUser.save();
    await toUser.save();
    return res.status(200).json({ message: "Friend request accepted (mutual)", autoAccepted: true });
  }

  // Add pending request to toUser
  toUser.friendRequests.push({ from: fromId, status: "pending" });
  await toUser.save();

  res.status(200).json({ message: "Friend request sent" });
});

// ─── Accept Friend Request ─────────────────────────────────────────────────────
// POST /api/friends/accept   { fromId }
const acceptRequest = catchAsync(async (req, res) => {
  const { fromId } = req.body;
  const meId = req.user.id;

  const me = await User.findOne({ id: meId });
  const them = await User.findOne({ id: Number(fromId) });

  if (!them) throw new ApiError(404, "User not found");

  const req_entry = me.friendRequests.find(r => r.from === Number(fromId) && r.status === "pending");
  if (!req_entry) throw new ApiError(400, "No pending friend request from this user");

  req_entry.status = "accepted";
  if (!me.friends.includes(Number(fromId))) me.friends.push(Number(fromId));
  if (!them.friends.includes(meId)) them.friends.push(meId);

  await me.save();
  await them.save();

  res.status(200).json({ message: "Friend request accepted" });
});

// ─── Decline / Cancel Friend Request ──────────────────────────────────────────
// POST /api/friends/decline   { fromId }
const declineRequest = catchAsync(async (req, res) => {
  const { fromId } = req.body;
  const meId = req.user.id;

  const me = await User.findOne({ id: meId });
  if (!me) throw new ApiError(404, "User not found");

  const before = me.friendRequests.length;
  me.friendRequests = me.friendRequests.filter(r => r.from !== Number(fromId));
  if (me.friendRequests.length === before) throw new ApiError(400, "No request found");

  await me.save();
  res.status(200).json({ message: "Friend request declined" });
});

// ─── Cancel outgoing request (sender cancels) ─────────────────────────────────
// POST /api/friends/cancel   { toId }
const cancelRequest = catchAsync(async (req, res) => {
  const { toId } = req.body;
  const meId = req.user.id;

  const them = await User.findOne({ id: Number(toId) });
  if (!them) throw new ApiError(404, "User not found");

  const before = them.friendRequests.length;
  them.friendRequests = them.friendRequests.filter(r => !(r.from === meId && r.status === "pending"));
  if (them.friendRequests.length === before) throw new ApiError(400, "No outgoing request found");

  await them.save();
  res.status(200).json({ message: "Friend request cancelled" });
});

// ─── Remove Friend ─────────────────────────────────────────────────────────────
// DELETE /api/friends/:friendId
const removeFriend = catchAsync(async (req, res) => {
  const meId = req.user.id;
  const friendId = Number(req.params.friendId);

  const me = await User.findOne({ id: meId });
  const them = await User.findOne({ id: friendId });

  if (!me || !them) throw new ApiError(404, "User not found");

  me.friends = me.friends.filter(id => id !== friendId);
  them.friends = them.friends.filter(id => id !== meId);

  // Also remove any accepted request entries
  me.friendRequests = me.friendRequests.filter(r => r.from !== friendId);
  them.friendRequests = them.friendRequests.filter(r => r.from !== meId);

  await me.save();
  await them.save();

  res.status(200).json({ message: "Friend removed" });
});

// ─── Get Friends + Pending Requests ────────────────────────────────────────────
// GET /api/friends
const getFriends = catchAsync(async (req, res) => {
  const meId = req.user.id;
  const me = await User.findOne({ id: meId });
  if (!me) throw new ApiError(404, "User not found");

  // Resolve friends into full user objects
  const friendUsers = await User.find({ id: { $in: me.friends } })
    .select("id username avatarUrl socketId");

  // Incoming pending requests — resolve sender info
  const incomingIds = me.friendRequests
    .filter(r => r.status === "pending")
    .map(r => r.from);

  const incomingUsers = await User.find({ id: { $in: incomingIds } })
    .select("id username avatarUrl");

  // Outgoing pending requests — find docs where MY id appears in their friendRequests
  const outgoingDocs = await User.find({
    "friendRequests": { $elemMatch: { from: meId, status: "pending" } }
  }).select("id username avatarUrl");

  res.status(200).json({
    friends: friendUsers.map(u => ({ id: u.id, username: u.username, avatarUrl: u.avatarUrl, socketId: u.socketId })),
    incoming: incomingUsers.map(u => ({ id: u.id, username: u.username, avatarUrl: u.avatarUrl })),
    outgoing: outgoingDocs.map(u => ({ id: u.id, username: u.username, avatarUrl: u.avatarUrl })),
  });
});

module.exports = { sendRequest, acceptRequest, declineRequest, cancelRequest, removeFriend, getFriends };

const bcrypt = require("bcrypt");
const jwt = require("jsonwebtoken");
const User = require("../models/User");
const ApiError = require("../utils/ApiError");
const catchAsync = require("../utils/catchAsync");
const { deleteImage } = require("../utils/cloudinaryHelper");

const SECRET = process.env.JWT_SECRET || "fallback-secret";

// ─── Signup ───────────────────────────────────────────────────────────────────
const signup = catchAsync(async (req, res) => {
  const { username, email, password, dob } = req.body;
  // Note: presence & format validated by Zod middleware (signupSchema)

  const existingUser = await User.findOne({ email });
  if (existingUser) {
    throw new ApiError(400, "User already exists");
  }

  const hashedPassword = await bcrypt.hash(password, 10);

  const newUser = new User({
    username,
    email,
    dob,
    password: hashedPassword,
  });

  await newUser.save();
  res.status(201).json({ message: "Account created successfully" });
});

// ─── Login ────────────────────────────────────────────────────────────────────
const login = catchAsync(async (req, res) => {
  const { email, password } = req.body;
  // Note: presence & format validated by Zod middleware (loginSchema)

  const user = await User.findOne({ email });

  if (!user) {
    throw new ApiError(404, "User not found");
  }

  // Guard: if user signed up via Google and hasn't set a password yet
  if (user.googleId && !user.password) {
    throw new ApiError(400, "No password set. Please add a password in Settings first.");
  }

  const isMatch = await bcrypt.compare(password, user.password);
  if (!isMatch) {
    throw new ApiError(401, "Invalid credentials");
  }

  const userId = user._doc?.id || user.id || user._id;

  const token = jwt.sign(
    { id: userId, username: user.username },
    SECRET,
    { expiresIn: "1h" }
  );

  res.status(200).json({
    message: "Login successful",
    token,
    user: { id: userId, username: user.username, email: user.email, dob: user.dob, hasPassword: !!user.password, avatarUrl: user.avatarUrl },
  });
});

// ─── Get User ─────────────────────────────────────────────────────────────────
const getUser = catchAsync(async (req, res) => {
  const id = Number(req.params.id);
  const user = await User.findOne({ id });

  if (!user) {
    throw new ApiError(404, "User not found");
  }

  res.status(200).json({
    id: user.id,
    username: user.username,
    email: user.email,
    dob: user.dob,
    hasPassword: !!user.password,
    avatarUrl: user.avatarUrl,
  });
});

// ─── Update User ──────────────────────────────────────────────────────────────
const updateUser = catchAsync(async (req, res) => {
  const id = Number(req.params.id);

  if (req.user.id != id) {
    throw new ApiError(403, "Unauthorized action");
  }

  const { username, email, password, dob, avatarUrl } = req.body;

  const user = await User.findOne({ id });
  if (!user) {
    throw new ApiError(404, "User not found");
  }

  // If avatar is being updated and an old one exists, cleanup Cloudinary
  if (avatarUrl !== undefined && avatarUrl !== user.avatarUrl) {
    await deleteImage(user.avatarUrl);
    user.avatarUrl = avatarUrl;
  }

  if (username) user.username = username;
  if (email) user.email = email;
  if (password) user.password = await bcrypt.hash(password, 10);
  if (dob) user.dob = dob;

  await user.save();

  res.status(200).json({
    message: "User updated successfully",
    user: { id: user.id, username: user.username, email: user.email, dob: user.dob, hasPassword: !!user.password, avatarUrl: user.avatarUrl },
  });
});

// ─── Delete User ──────────────────────────────────────────────────────────────
const deleteUser = catchAsync(async (req, res) => {
  const id = Number(req.params.id);

  if (req.user.id != id) {
    throw new ApiError(403, "You can only delete your own account");
  }

  const user = await User.findOne({ id });
  if (user) {
    await deleteImage(user.avatarUrl);
  }

  const result = await User.deleteOne({ id });

  if (result.deletedCount === 0) {
    throw new ApiError(404, "User not found");
  }

  res.status(200).json({ message: "Account deleted successfully" });
});

// ─── Friend System ────────────────────────────────────────────────────────────
const sendFriendRequest = catchAsync(async (req, res) => {
  const { username } = req.body;
  const currentUserId = req.user.id || req.user._id || req.user.userId;

  if (!currentUserId) {
    throw new ApiError(400, "Authentication error: Missing user ID in token");
  }

  if (!username) {
    throw new ApiError(400, "Username is required");
  }

  const currentUser = await User.findOne({ id: currentUserId });
  const targetUser = await User.findOne({ username });

  if (!targetUser) {
    throw new ApiError(404, "User not found");
  }

  if (targetUser.id === currentUserId) {
    throw new ApiError(400, "You cannot send a friend request to yourself");
  }

  if (targetUser.friends && targetUser.friends.includes(currentUserId)) {
    throw new ApiError(400, "You are already friends with this user");
  }

  // Check if target user already has a pending request from current user
  const existingRequest = targetUser.friendRequests && targetUser.friendRequests.find(r => r.fromId === currentUserId && r.status === 'pending');
  if (existingRequest) {
    throw new ApiError(400, "Friend request already sent");
  }

  // Add friend request to target user
  if (!targetUser.friendRequests) targetUser.friendRequests = [];
  targetUser.friendRequests.push({ fromId: currentUserId, status: 'pending' });
  await targetUser.save();

  // Socket notification will be handled in the route or controller later if we have socket instance
  // For now we can use req.app.get('io') to emit
  const io = req.app.get("io");
  if (io) {
    // We emit to the target user's rooms (userId is used as room or we broadcast to their socket directly if mapped)
    // Looking at server.js, users aren't joining rooms by userId, but we can emit to specific socketId.
    // Actually, we can just emit an event, but `server.js` manages `userSockets`. We'll broadcast `friend-request-received` and the client will filter, OR we can emit globally and let clients filter.
    io.emit('friend-request-received', { targetUserId: targetUser.id, fromUser: { id: currentUser.id, username: currentUser.username, avatarUrl: currentUser.avatarUrl } });
  }

  res.status(200).json({ message: "Friend request sent" });
});

const acceptFriendRequest = catchAsync(async (req, res) => {
  const { fromId } = req.body;
  const currentUserId = req.user.id || req.user._id || req.user.userId;

  const currentUser = await User.findOne({ id: currentUserId });
  const fromUser = await User.findOne({ id: fromId });

  if (!fromUser) {
    throw new ApiError(404, "User not found");
  }

  // Find the pending request
  const requestIndex = currentUser.friendRequests.findIndex(r => r.fromId === fromId && r.status === 'pending');
  if (requestIndex === -1) {
    throw new ApiError(400, "No pending friend request found");
  }

  // Update status
  currentUser.friendRequests[requestIndex].status = 'accepted';

  // Add to friends lists
  if (!currentUser.friends.includes(fromId)) currentUser.friends.push(fromId);
  if (!fromUser.friends.includes(currentUserId)) fromUser.friends.push(currentUserId);

  await currentUser.save();
  await fromUser.save();

  const io = req.app.get("io");
  if (io) {
    io.emit('friend-request-accepted', {
      targetUserId: fromId,
      fromUser: { id: currentUser.id, username: currentUser.username, avatarUrl: currentUser.avatarUrl }
    });
  }

  res.status(200).json({ message: "Friend request accepted" });
});

const rejectFriendRequest = catchAsync(async (req, res) => {
  const { fromId } = req.body;
  const currentUserId = req.user.id || req.user._id || req.user.userId;

  const currentUser = await User.findOne({ id: currentUserId });

  // Find the pending request
  const requestIndex = currentUser.friendRequests.findIndex(r => r.fromId === fromId && r.status === 'pending');
  if (requestIndex === -1) {
    throw new ApiError(400, "No pending friend request found");
  }

  // Update status or remove it. Let's just remove it or set to rejected
  currentUser.friendRequests[requestIndex].status = 'rejected';
  await currentUser.save();

  res.status(200).json({ message: "Friend request rejected" });
});

const getFriendsAndRequests = catchAsync(async (req, res) => {
  const currentUserId = req.user.id || req.user._id || req.user.userId;
  const currentUser = await User.findOne({ id: currentUserId });

  if (!currentUser) throw new ApiError(404, "User not found");

  // Fetch friends details
  const friends = await User.find({ id: { $in: currentUser.friends || [] } }, 'id username avatarUrl');

  // Fetch pending requests details
  const pendingRequests = (currentUser.friendRequests || []).filter(r => r.status === 'pending');
  const fromIds = pendingRequests.map(r => r.fromId);

  const pendingUsers = await User.find({ id: { $in: fromIds } }, 'id username avatarUrl');

  const requests = pendingRequests.map(req => {
    const u = pendingUsers.find(user => user.id === req.fromId);
    return {
      fromId: req.fromId,
      username: u ? u.username : 'Unknown',
      avatarUrl: u ? u.avatarUrl : null,
      createdAt: req.createdAt
    };
  });

  res.status(200).json({ friends, friendRequests: requests });
});

module.exports = { signup, login, getUser, updateUser, deleteUser, sendFriendRequest, acceptFriendRequest, rejectFriendRequest, getFriendsAndRequests };

