const mongoose = require("mongoose");

/**
 * Stores metadata for every file uploaded via the /api/upload endpoint.
 * Cloudinary is the actual storage backend; this record lets us track,
 * audit, and (optionally) delete assets later.
 */
const attachmentSchema = new mongoose.Schema(
  {
    publicId: {
      type: String,
      required: true, // Cloudinary public_id — needed to delete the asset
    },
    url: {
      type: String,
      required: true, // Cloudinary secure_url returned after upload
    },
    originalName: {
      type: String,
      default: "file",
    },
    mimeType: {
      type: String,
      default: "application/octet-stream",
    },
    size: {
      type: Number,
      default: 0, // bytes
    },
    resourceType: {
      type: String,
      enum: ["image", "video", "raw"],
      default: "raw",
    },
    uploadedBy: {
      type: Number, // matches User.id (numeric)
      default: null,
    },
  },
  { timestamps: true }
);

module.exports = mongoose.model("Attachment", attachmentSchema);

const mongoose = require("mongoose");

const directMessageSchema = new mongoose.Schema(
  {
    id: {
      type: Number,
      default: () => Date.now(),
      unique: true,
    },
    participants: {
      type: [Number],
      required: true,
      validate: {
        validator: (arr) => Array.isArray(arr) && arr.length === 2 && arr[0] !== arr[1],
        message: "participants must contain exactly two different user ids",
      },
    },
    senderId: {
      type: Number,
      required: true,
    },
    content: {
      type: String,
      default: "",
    },
    attachmentUrl: {
      type: String,
      default: null,
    },
    attachmentName: {
      type: String,
      default: null,
    },
    attachmentMimeType: {
      type: String,
      default: null,
    },
    type: {
      type: String,
      enum: ["user", "system"],
      default: "user",
    },
    systemKind: {
      type: String,
      enum: ["generic", "call_started"],
      default: "generic",
    },
    timestamp: {
      type: Date,
      default: Date.now,
    },
  },
  { timestamps: true }
);

directMessageSchema.index({ participants: 1, timestamp: 1 });

module.exports = mongoose.model("DirectMessage", directMessageSchema);

